mapper.update:
/* wms-master-account-sql-oracle.xml  updateTTMstAc */
	UPDATE TT_MST_AC
	   SET   ADDRESS1       		= #{address1}
			,ADDRESS2       		= #{address2}
			,ZIPCODE        		= #{zipcode}

			,ACTYPE					= #{actype}
			,ACNAME        	 		= #{acname}
			,REGNO       			= #{regno}
	        ,BUSINESSTYPE   		= #{businesstype}
	        ,BUSINESSCATEGORY		= #{businesscategory}     
	        ,COUNTRYCODE    		= #{countrycode}
	        ,CITY         			= #{city}  
	        ,STATE          		= #{state}
	        ,TEL1           		= #{tel1}       
	        ,TEL2           		= #{tel2}       
	        ,FAX            		= #{fax}        
	        ,CONTACT        		= #{contact}    
	        ,CEO            		= #{ceo} 
	        ,UDF1            		= #{udf1} 
	        ,UDF2            		= #{udf2} 
	        ,UDF3            		= #{udf3}        
			,REP_ACKEY				= #{repAckey}
	        ,REP_ACTYPE				= #{repActype}
	        ,ICGRKEY				= #{icgrkey}
	        ,ADDRID					= #{addrid}
	        ,REGDATE				= #{regdate}
	        ,EMAIL					= #{email}
	        ,ASNUSEYN				= #{asnuseyn}
		 	,DELYN					= #{delyn}
	        ,CLOSDATE    		= #{closdate}
			,CUST_TYPE				= #{custType}
			,CUST_TYPE_DETAIL		= #{custTypeDetail}

	        ,UPDATEDATE     		= #{sysdate}
	        ,UPDATEURKEY    		= #{surkey}
	 WHERE 
	 	   ACKEY = #{ackey}
	   AND OWKEY = #{owkey}

