	INSERT INTO TT_MST_ACXCT
	(
		  UPDATEURKEY
		 ,UPDATEDATE
		 ,INSERTURKEY
		 ,INSERTDATE
		 ,CTKEY
		 ,ACKEY
		 ,STOREORDTYPE
		 ,ACICGRTYPE
		 ,ICGRKEY
		 ,DCKEY
		 ,OWKEY
		 ,DELYN
	 )VALUES(
		  #{surkey}
		 ,#{sysdate}
		 ,#{surkey}
		 ,#{sysdate}
		 ,#{ctkey}
		 ,#{ackey}
		 ,'0'
		 ,'0'
		 ,'02'
		 ,#{dckey}
		 ,#{owkey}
		 ,'N'
	 )

